oldWay:
/* Media queries check viewport width — breaks
   when the component sits in a narrow column */
@media (min-width: 600px) {
  .card { flex-direction: row; }
}

startingCSS:
.scene {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.wrapper {
  /* Add container-type: inline-size here */
  background: #f1f5f9;
  border-radius: 10px;
  padding: 1rem;
}

.narrow { width: 220px; }
.wide   { width: 380px; }

.label {
  font-size: 0.7rem;
  font-weight: 600;
  color: #94a3b8;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin: 0 0 0.5rem;
}

.card {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  padding: 1rem;
  background: white;
  border-radius: 8px;
  border: 2px solid #e2e8f0;
}

.avatar {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: #a855f7;
  flex-shrink: 0;
}

.info strong {
  display: block;
  font-size: 0.875rem;
  margin-bottom: 0.2rem;
  color: #1f2937;
}

.info p {
  margin: 0;
  font-size: 0.75rem;
  color: #94a3b8;
}

@container (min-width: 300px) {
  .card {
    flex-direction: row;
    align-items: center;
  }
}
